using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void Setup() => _registry = new ServiceRegistry();

    // --- Registration ---

    [TestMethod]
    public void Register_ThenResolve_ReturnsService()
    {
        var service = new FakeLogger();

        _registry.Register<ILogger>(service);

        Assert.IsNotNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Register_OverwritesPreviousRegistration()
    {
        var first = new FakeLogger();
        var second = new FakeLogger();

        _registry.Register<ILogger>(first);
        _registry.Register<ILogger>(second);

        Assert.AreSame(second, _registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Register_NullService_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _registry.Register<ILogger>(null!));
    }

    // --- Resolution returns same instance ---

    [TestMethod]
    public void Resolve_ReturnsSameInstanceThatWasRegistered()
    {
        var service = new FakeLogger();

        _registry.Register<ILogger>(service);

        Assert.AreSame(service, _registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Resolve_CalledTwice_ReturnsSameReference()
    {
        _registry.Register<ILogger>(new FakeLogger());

        var first = _registry.Resolve<ILogger>();
        var second = _registry.Resolve<ILogger>();

        Assert.AreSame(first, second);
    }

    // --- Null for unregistered services ---

    [TestMethod]
    public void Resolve_UnregisteredService_ReturnsNull()
    {
        Assert.IsNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void ResolveRequired_UnregisteredService_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _registry.ResolveRequired<ILogger>());
    }

    // --- Clear ---

    [TestMethod]
    public void Clear_RemovesAllRegistrations()
    {
        _registry.Register<ILogger>(new FakeLogger());
        _registry.Register<ICache>(new FakeCache());

        _registry.Clear();

        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    [TestMethod]
    public void Clear_ResolveReturnsNull()
    {
        _registry.Register<ILogger>(new FakeLogger());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<ILogger>());
    }

    // --- Removal ---

    [TestMethod]
    public void Remove_RegisteredService_ResolveReturnsNull()
    {
        _registry.Register<ILogger>(new FakeLogger());

        _registry.Remove<ILogger>();

        Assert.IsNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Remove_OnlyAffectsTargetService()
    {
        var cache = new FakeCache();
        _registry.Register<ILogger>(new FakeLogger());
        _registry.Register<ICache>(cache);

        _registry.Remove<ILogger>();

        Assert.AreSame(cache, _registry.Resolve<ICache>());
    }

    [TestMethod]
    public void Remove_UnregisteredService_DoesNotThrow()
    {
        _registry.Remove<ILogger>();

        // reaching here without exception is the assertion
        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    // --- Test doubles ---

    private interface ILogger { }
    private interface ICache { }
    private sealed class FakeLogger : ILogger { }
    private sealed class FakeCache : ICache { }
}

